callGraph.callee:
(() => {
								const meta = LAST_RUN_META[lastRunStatus];
								const cell = (
									<span
										className={cn(
											"flex items-center gap-1.5",
											meta.failed && "text-red-600 dark:text-red-400",
										)}
									>
										<span
											className={cn(
												"inline-block size-1.5 shrink-0 rounded-full",
												meta.dot,
											)}
										/>
										{meta.label}
									</span>
								);
								return meta.failed ? (
									<Tooltip>
										<TooltipTrigger asChild>{cell}</TooltipTrigger>
										<TooltipContent>
											The last run failed. Click to see why.
										</TooltipContent>
									</Tooltip>
								) : (
									cell
								);
							})

inspect()
			.then((preview) => {
				if (cancelled) return;
				setInspectState({ status: "ready", preview });
			})
			.catch

childEntries
			.sort((left, right) => {
				const leftLocalMain =
					left.child.type === "workspace" &&
					isLocalMainWorkspace(left.child.workspace);
				const rightLocalMain =
					right.child.type === "workspace" &&
					isLocalMainWorkspace(right.child.workspace);
				if (leftLocalMain !== rightLocalMain) {
					return leftLocalMain ? -1 : 1;
				}
				return left.tabOrder - right.tabOrder;
			})
			.map
